package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.Indexator;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManagerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.PersoonsDataManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.NlpPrestatie;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Persoon;
import com.google.common.collect.ArrayListMultimap;
import com.google.common.collect.Multimap;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.BETALING_VOORSCHOT_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.LooncodeGroepKeyStrings.INH_WERKUITKERING_UREN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INDEXATOR_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.INHOUDINGEN_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONCODE_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOONSDATA_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class BerekenVoorschot extends BerekenInhoudingen {

    public BerekenVoorschot(ConstantManager constantManager, NlpGlobalService service) {
        super(constantManager, service);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        mainContext.put(LOONELEMENT_MANAGER_KEY, new LoonElementManagerImp());
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Indexator indexator = new Indexator(constantManager, rekenTijd.eindDatum);
        mainContext.put(INDEXATOR_KEY, indexator);

        Set<Opdracht> opdrachten = persoon.getOpdrachten();
        for (Opdracht opdracht : opdrachten) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            opdrachtContext.put(OPPER_LAATSTE_GEGEVENS_KEY, RekenTools.getOpperLaatsteGegevens(opdracht));
            for (Opper opper : opdracht.getOpperSlices()) {
                leesPrestaties(opdrachtContext, opper);
                berekenInhoudingen(opdrachtContext, opper);
            }
        }
        return CONTINUE_PROCESSING;
    }

    public void leesPrestaties(RekenContext context, Opper opper) {
        RekenTijd rekenTijd = context.getUnchecked(REKENTIJD_KEY);

        PersoonsDataManager dataManager = context.getUnchecked(PERSOONSDATA_MANAGER_KEY);
        LoonCodeManager loonCodeManager = context.getUnchecked(LOONCODE_MANAGER_KEY);
        List<NlpPrestatie> prestaties = dataManager.findPrestaties(opper, rekenTijd.eindDatum);
        List<NlpPrestatie> inhoudingen = new ArrayList<>();

        for (NlpPrestatie prestatie : prestaties) {
            AardKodeExtensie looncode = loonCodeManager.getByPrestatie(prestatie);
            if (looncode.behoortTotGroep(BETALING_VOORSCHOT_KEY)) {
                inhoudingen.add(prestatie);
            }
        }

        context.putDoubleKey(INHOUDINGEN_KEY, opper, inhoudingen);
    }

    @Override
    protected Multimap<AardKodeExtensie, NlpPrestatie> vormInhoudingenMap(LoonCodeManager loonCodeManager, List<NlpPrestatie> inhoudingen) {
        Multimap<AardKodeExtensie, NlpPrestatie> inhoudingMap = ArrayListMultimap.create();
        for (NlpPrestatie inhouding : inhoudingen) {
            AardKodeExtensie aardKodeExtensie = loonCodeManager.getByPrestatie(inhouding);
            if (!aardKodeExtensie.behoortTotGroep(INH_WERKUITKERING_UREN_KEY)) {
                inhoudingMap.put(aardKodeExtensie, inhouding);
            }
        }
        return inhoudingMap;
    }

}
